const alerts = $json.sms_alerts || [];
const twilioFromNumber = $('Build Workflow Config1').first().json.twilio_from_number;

return alerts.flatMap((alert) => {
  const users = alert.users || [];
  return users.map((user) => ({
    json: {
      listing_id: alert.listing_id,
      to: user.phone,
      body: alert.body,
      user_key: user.key,
      twilio_from_number: twilioFromNumber
    }
  }));
});

const items = $input.all();
const out = [];
const seenEmailIds = new Set();

function headerValue(headers, name) {
  const match = (headers || []).find((header) => String(header.name || '').toLowerCase() === name);
  return match ? String(match.value || '') : '';
}

for (const item of items) {
  const json = item.json || {};
  const payload = json.payload || {};
  const headers = Array.isArray(payload.headers) ? payload.headers : [];
  const emailId = String(json.id || '').trim();
  if (!emailId || seenEmailIds.has(emailId)) continue;
  seenEmailIds.add(emailId);

  const from = String(json.From || json.from || headerValue(headers, 'from') || '').trim().toLowerCase();
  const subject = String(json.Subject || json.subject || headerValue(headers, 'subject') || '').trim();
  const snippet = String(json.snippet || '').trim();
  const internalDate = String(json.internalDate || '').trim();

  let source = null;
  if (from.includes('alerts@alerts.craigslist.org')) source = 'craigslist';
  else if (from.includes('mail.zillow.com')) source = 'zillow';
  else if (from.includes('apartments.com')) source = 'apartments_com';
  else continue;

  out.push({
    json: {
      email_id: emailId,
      source,
      email_from: from,
      email_subject: subject,
      snippet,
      internal_date: internalDate
    }
  });
}

return out;

const items = $input.all();
const out = [];

function decodeBase64Url(value) {
  if (!value) return '';
  const normalized = String(value).replace(/-/g, '+').replace(/_/g, '/');
  const pad = normalized.length % 4;
  const padded = pad ? normalized + '='.repeat(4 - pad) : normalized;
  return Buffer.from(padded, 'base64').toString('utf8');
}

function decodeQuotedPrintable(value) {
  return String(value || '')
    .replace(/=\r\n/g, '')
    .replace(/=\n/g, '')
    .replace(/=([0-9A-F]{2})/gi, function (_, hex) { return String.fromCharCode(parseInt(hex, 16)); });
}

function htmlEntityDecode(value) {
  return String(value || '')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&apos;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&#x2F;/gi, '/')
    .replace(/&#47;/gi, '/');
}

function decodeText(value) {
  return htmlEntityDecode(decodeQuotedPrintable(value || ''));
}

function decodePart(part) {
  return decodeText(decodeBase64Url(part && part.body ? part.body.data || '' : ''));
}

function collectParts(part, bucket) {
  if (!part) return;
  const mimeType = String(part.mimeType || '').toLowerCase();
  const decoded = decodePart(part);
  if (decoded) {
    if (mimeType.includes('text/plain')) bucket.textPlain.push(decoded);
    if (mimeType.includes('text/html')) bucket.textHtml.push(decoded);
  }
  if (Array.isArray(part.parts)) {
    for (const child of part.parts) collectParts(child, bucket);
  }
}

function extractUrls(text) {
  return Array.from(String(text || '').matchAll(/https?:\/\/[^\s"'<>]+/gi)).map(function (match) {
    return match[0].replace(/[),.]+$/, '');
  });
}

function tryDecode(value) {
  try {
    return decodeURIComponent(value);
  } catch {
    return value;
  }
}

function expandUrl(url) {
  const seen = new Set();
  const queue = [String(url || '').trim()];
  const results = [];

  while (queue.length) {
    const current = queue.shift();
    if (!current || seen.has(current)) continue;
    seen.add(current);
    results.push(current);

    const decoded = tryDecode(current);
    if (decoded && !seen.has(decoded)) queue.push(decoded);

    const match = current.match(/[?&](?:target|url|u|q|dest|destination|redirect)=([^&]+)/i);
    if (match && match[1]) {
      queue.push(match[1]);
      queue.push(tryDecode(match[1]));
    }
  }

  return results;
}

function detectSource(from) {
  const lower = String(from || '').toLowerCase();
  if (lower.includes('craigslist.org')) return 'craigslist';
  if (lower.includes('zillow.com')) return 'zillow';
  if (lower.includes('apartments.com')) return 'apartments_com';
  return null;
}

function isCraigslistListing(url) {
  const value = String(url || '').toLowerCase();
  return value.includes('craigslist.org/') && !value.includes('accounts.craigslist.org') && value.includes('/d/') && value.endsWith('.html');
}

function isZillowListing(url) {
  const value = String(url || '').toLowerCase();
  return value.includes('zillow.com/')
    && !value.includes('click.mail.zillow.com/')
    && !value.includes('/email/feedback')
    && !value.includes('/email/unsubscribe')
    && !value.includes('zillowgroup.com')
    && !value.includes('/myzillow/')
    && !value.includes('/homes/for_rent/')
    && (value.includes('/apartments/') || value.includes('/homedetails/') || value.includes('/routing/email/property-notifications/'));
}

function isApartmentsListing(url) {
  const value = String(url || '').toLowerCase();
  return value.includes('apartments.com/') && !value.includes('/account') && !value.includes('/login') && !value.includes('unsubscribe');
}

function keepUrlForSource(source, url) {
  if (source === 'craigslist') return isCraigslistListing(url);
  if (source === 'zillow') return isZillowListing(url);
  if (source === 'apartments_com') return isApartmentsListing(url);
  return false;
}

function cleanUrl(source, url) {
  try {
    const parsed = new URL(url);
    parsed.hash = '';
    const keys = Array.from(parsed.searchParams.keys());
    for (const key of keys) {
      const lower = key.toLowerCase();
      if (lower.startsWith('utm_') || lower === 'rtoken' || lower === 'z' || lower === 'sseid') {
        parsed.searchParams.delete(key);
      }
    }
    return parsed.toString();
  } catch {
    return String(url || '').trim();
  }
}

function scoreUrl(source, url) {
  const value = String(url || '').toLowerCase();
  if (source === 'craigslist') return 100;
  if (source === 'zillow') {
    if (value.includes('/homedetails/')) return 100;
    if (value.includes('/apartments/')) return 90;
    if (value.includes('/routing/email/property-notifications/')) return 80;
  }
  if (source === 'apartments_com') return 70;
  return 0;
}

function chooseUrl(source, urls) {
  const unique = Array.from(new Set(urls.map(function (url) { return cleanUrl(source, url); }).filter(Boolean)));
  unique.sort(function (left, right) { return scoreUrl(source, right) - scoreUrl(source, left); });
  return unique[0] || '';
}

function normalizedLines(text) {
  return String(text || '')
    .replace(/\r/g, '\n')
    .split('\n')
    .map(function (line) { return line.replace(/\s+/g, ' ').trim(); })
    .filter(Boolean);
}

function parseMoney(text) {
  const match = String(text || '').match(/\$([\d,]+)\s*\/mo/i);
  return match ? parseInt(match[1].replace(/,/g, ''), 10) : null;
}

function detectFeatures(text) {
  const haystack = String(text || '').toLowerCase();
  const features = [];
  if (/dishwasher/.test(haystack)) features.push('dishwasher');
  if (/in[-\s]?unit laundry|washer\/dryer in unit|w\/d in unit/.test(haystack)) features.push('in-unit laundry');
  if (/parking|garage/.test(haystack)) features.push('parking');
  if (/fitness center|gym/.test(haystack)) features.push('fitness center');
  if (/pet friendly|cats? ok|dogs? ok/.test(haystack)) features.push('pet friendly');
  if (/balcony|patio|deck|terrace/.test(haystack)) features.push('private outdoor space');
  return features;
}

function extractZillowMetadata(subject, snippet, plainText, listingUrl) {
  const combined = [subject, snippet, plainText].filter(Boolean).join('\n');
  const lines = normalizedLines(combined);
  const statsMatch = combined.match(/(\d+(?:\.\d+)?)\s*bd\s*\|\s*(\d+(?:\.\d+)?)\s*ba\s*\|\s*([\d,]+)\s*sqft/i);
  const addressLine = lines.find(function (line) {
    return /,\s*CA\b/i.test(line) && (/^\d/.test(line) || /\bAPT\b/i.test(line));
  }) || null;
  const features = detectFeatures(combined);
  return {
    listing_url: listingUrl,
    source_listing_id: listingUrl,
    address: addressLine,
    rent: parseMoney(combined),
    beds: statsMatch ? Number(statsMatch[1]) : null,
    baths: statsMatch ? Number(statsMatch[2]) : null,
    sqft: statsMatch ? parseInt(statsMatch[3].replace(/,/g, ''), 10) : null,
    description: subject || snippet || '',
    features: features,
    has_dishwasher: features.includes('dishwasher'),
    has_in_unit_laundry: features.includes('in-unit laundry'),
    has_parking: features.includes('parking'),
    pet_friendly: features.includes('pet friendly'),
    has_private_outdoor_space: features.includes('private outdoor space'),
    has_fitness_center: features.includes('fitness center'),
    caltrain_signal: /caltrain/i.test(combined),
    walkability_signal: /walk to|walkable/i.test(combined)
  };
}

for (const item of items) {
  const json = item.json || {};
  const payload = json.payload || {};
  const headers = Array.isArray(payload.headers) ? payload.headers : [];
  const headerMap = Object.fromEntries(headers.map(function (h) {
    return [String(h.name || '').toLowerCase(), String(h.value || '')];
  }));

  const emailId = String(json.id || '').trim();
  const from = String(headerMap.from || '').toLowerCase();
  const subject = String(headerMap.subject || '');
  const snippet = decodeText(String(json.snippet || ''));
  const source = detectSource(from);
  if (!source) continue;

  const bucket = { textPlain: [], textHtml: [] };
  collectParts(payload, bucket);

  const rawUrls = [].concat(
    extractUrls(subject),
    extractUrls(snippet),
    bucket.textPlain.flatMap(extractUrls),
    bucket.textHtml.flatMap(extractUrls)
  );

  const chosenUrl = chooseUrl(
    source,
    rawUrls.flatMap(expandUrl).filter(function (url) { return keepUrlForSource(source, url); })
  );

  const base = {
    version: 'extract-email-seeds-v1',
    email_id: emailId,
    source: source,
    email_from: from,
    email_subject: subject,
    snippet: snippet,
    listing_url: chosenUrl,
    url_found: Boolean(chosenUrl)
  };

  if (!chosenUrl) {
    out.push({ json: base });
    continue;
  }

  if (source === 'zillow') {
    const metadata = extractZillowMetadata(subject, snippet, bucket.textPlain.join('\n'), chosenUrl);
    out.push({ json: Object.assign({}, base, metadata) });
    continue;
  }

  out.push({ json: base });
}

return out;

const items = $input.all().filter(function (item) {
  return item.json && item.json.url_found && item.json.listing_url;
});

const sourceSeeds = {
  craigslist: [],
  zillow: [],
  apartments_com: []
};

const seen = {
  craigslist: new Set(),
  zillow: new Set(),
  apartments_com: new Set()
};

for (const item of items) {
  const row = item.json || {};
  if (!sourceSeeds[row.source]) continue;

  if (row.source === 'zillow') {
    const key = String(row.listing_url || '').trim();
    if (!key || seen.zillow.has(key)) continue;
    seen.zillow.add(key);
    sourceSeeds.zillow.push({
      listing_url: key,
      source_listing_id: row.source_listing_id || key,
      address: row.address || null,
      rent: row.rent ?? null,
      beds: row.beds ?? null,
      baths: row.baths ?? null,
      sqft: row.sqft ?? null,
      description: row.description || '',
      features: Array.isArray(row.features) ? row.features : [],
      has_dishwasher: Boolean(row.has_dishwasher),
      has_in_unit_laundry: Boolean(row.has_in_unit_laundry),
      has_parking: Boolean(row.has_parking),
      pet_friendly: Boolean(row.pet_friendly),
      has_private_outdoor_space: Boolean(row.has_private_outdoor_space),
      has_fitness_center: Boolean(row.has_fitness_center),
      caltrain_signal: Boolean(row.caltrain_signal),
      walkability_signal: Boolean(row.walkability_signal)
    });
    continue;
  }

  const key = String(row.listing_url || '').trim();
  if (!key || seen[row.source].has(key)) continue;
  seen[row.source].add(key);
  sourceSeeds[row.source].push(key);
}

const totalSeeds = Object.values(sourceSeeds).reduce(function (sum, values) {
  return sum + values.length;
}, 0);

if (totalSeeds === 0) {
  return [];
}

return [{
